package com.eas.ui.admin;
import com.eas.config.Database; import com.eas.model.UserSession; import com.eas.service.AuditService; import com.eas.util.*; import java.awt.*; import java.sql.*; import javax.swing.*;
public class AttendanceManagementPanel extends ReadOnlyQueryPanel { private final UserSession session; private final JTextField employeeId=new JTextField(8), date=new JTextField(10), shiftId=new JTextField(7), locationId=new JTextField(7), remarks=new JTextField(20); private final JComboBox<String> status=new JComboBox<String>(new String[]{"ABSENT","PRESENT","ON_LEAVE","REST_DAY","HOLIDAY"});
 public AttendanceManagementPanel(UserSession s){super("Daily Attendance Monitoring","SELECT * FROM v_daily_attendance ORDER BY attendance_date DESC,id DESC","SELECT * FROM v_daily_attendance WHERE employee_no LIKE ? OR full_name LIKE ? OR attendance_status LIKE ? ORDER BY attendance_date DESC,id DESC","daily_attendance");session=s;JPanel p=new JPanel();p.setBorder(BorderFactory.createTitledBorder("Manual Attendance Marking"));p.add(new JLabel("Employee ID"));p.add(employeeId);p.add(new JLabel("Date YYYY-MM-DD"));p.add(date);p.add(new JLabel("Shift ID"));p.add(shiftId);p.add(new JLabel("Location ID"));p.add(locationId);p.add(status);p.add(remarks);JButton save=UITheme.button("SAVE/UPDATE STATUS");p.add(save);add(p,BorderLayout.SOUTH);save.addActionListener(e->save());}
 private void save(){String q="INSERT INTO attendance_records(employee_id,attendance_date,shift_id,location_id,attendance_status,remarks) VALUES(?,?,?,?,?,?) ON DUPLICATE KEY UPDATE shift_id=VALUES(shift_id),location_id=VALUES(location_id),attendance_status=VALUES(attendance_status),remarks=VALUES(remarks)";try(Connection c=Database.getConnection();PreparedStatement p=c.prepareStatement(q)){p.setInt(1,Integer.parseInt(employeeId.getText().trim()));p.setString(2,date.getText().trim());p.setString(3,shiftId.getText().trim());p.setString(4,locationId.getText().trim());p.setString(5,status.getSelectedItem().toString());p.setString(6,remarks.getText().trim());p.executeUpdate();AuditService.log(session.getId(),"MARK_ATTENDANCE","ATTENDANCE","Manual attendance entry recorded.");load("");Dialogs.info(this,"Attendance saved.");}catch(Exception ex){Dialogs.error(this,ex.getMessage());}}
}
